const rows = $input.all();
let text = '';
if (rows.length === 0 || !rows[0].json.post_title) {
  text = 'No Substack posts found to use as context.';
} else {
  text = 'Use the following recent Substack articles as context/ideas for generating a LinkedIn post:\n\n';
  rows.forEach((row, index) => {
    const p = row.json;
    text += `[Article #${index + 1}]\nTitle: ${p.post_title}\nURL: ${p.post_url}\nContent snippet: ${(p.post_content || '').substring(0, 3000)}\n\n`;
  });
}

const fs = require('fs');
let persona = '';
try {
  persona = fs.readFileSync('/etc/n8n/giusy.md', 'utf8');
} catch (e) {
  persona = 'Warm, brilliant AI Marketing Director named Giusy.';
}

return [{ json: { text, giusy_persona: persona } }];

const raw = $input.first().json.content || $input.first().json.response || '';
let jsonStr = raw.trim();
const firstBrace = jsonStr.indexOf('{');
const lastBrace = jsonStr.lastIndexOf('}');
if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
  jsonStr = jsonStr.substring(firstBrace, lastBrace + 1);
}

jsonStr = jsonStr.replace(/[\u201C\u201D\u201E\u201F\u2033\u2036]/g, '"');

let parsed;
try {
  parsed = JSON.parse(jsonStr);
} catch (e) {
  parsed = { linkedin_post: raw, brief_strategic_reasoning: 'Fallback parsing.' };
}

return [{ json: { linkedin_post: parsed.linkedin_post, reasoning: parsed.brief_strategic_reasoning || '' } }];

